define('taoMediaManager/qtiCreator/helper/sharedStimulusLoader',['jquery', 'taoQtiItem/qtiItem/core/Loader', 'taoQtiItem/qtiCreator/model/qtiClasses', 'taoMediaManager/qtiCreator/helper/createDummyItemData', 'core/dataProvider/request', 'util/url', 'taoMediaManager/qtiCreator/helper/formatStyles'], function ($, Loader, qtiClasses, creatorDummyItemData, request, urlUtil, formatStyles) {
  'use strict';

  var qtiNamespace = 'http://www.imsglobal.org/xsd/imsqti_v2p2';
  var qtiSchemaLocation = {
    'http://www.imsglobal.org/xsd/imsqti_v2p2': 'http://www.imsglobal.org/xsd/qti/qtiv2p2/imsqti_v2p2.xsd'
  };
  var languagesUrl = urlUtil.route('index', 'Languages', 'tao');
  var creatorLoader = {
    loadSharedStimulus(config, callback) {
      if (config.id) {
        var languagesList = request(languagesUrl);
        var assetData = request(config.assetDataUrl, {
          id: config.id
        });
        var assetStyles = request(config.assetDataStyles, {
          uri: config.id
        });
        Promise.all([languagesList, assetData, assetStyles]).then(values => {
          var loader, itemData;
          itemData = creatorDummyItemData(values[1]);
          if (values[2].children.length) {
            values[2].children.forEach((stylesheet, index) => {
              if (stylesheet.name !== 'tao-user-styles.css') {
                var serial = "creator_".concat(index);
                var link = urlUtil.route('loadStylesheet', 'SharedStimulusStyling', 'taoMediaManager', {
                  uri: config.id,
                  stylesheet: stylesheet.name
                });
                itemData.stylesheets[serial] = {
                  qtiClass: 'stylesheet',
                  attributes: {
                    href: link,
                    media: 'all',
                    title: stylesheet.name,
                    type: 'text/css',
                    onload: e => formatStyles.handleStylesheetLoad(e)
                  },
                  serial,
                  getComposingElements: () => ({})
                };
              }
            });
          }
          loader = new Loader().setClassesLocation(qtiClasses);
          loader.loadItemData(itemData, function (loadedItem) {
            var namespaces;
            namespaces = loadedItem.getNamespaces();
            namespaces[''] = qtiNamespace;
            loadedItem.setNamespaces(namespaces);
            loadedItem.setSchemaLocations(qtiSchemaLocation);
            if (languagesList) {
              loadedItem.data('languagesList', values[0]);
            }
            callback(loadedItem, this.getLoadedClasses());
          });
        });
      }
    }
  };
  return creatorLoader;
});
