define('taoMediaManager/qtiCreator/plugins/navigation/back',['jquery', 'i18n', 'core/plugin', 'ui/hider', 'tpl!taoQtiItem/qtiCreator/plugins/button'], function ($, __, pluginFactory, hider, buttonTpl) {
  'use strict';
  return pluginFactory({
    name: 'back',
    init() {
      var sharedStimulusCreator = this.getHost();
      sharedStimulusCreator.on('exit', function () {
        window.history.back();
      });
      this.$element = $(buttonTpl({
        icon: 'left',
        title: __('Back to Manage Assets'),
        text: __('Manage Assets'),
        cssClass: 'back-action',
        testId: 'manage-assets'
      })).on('click', function backHandler(e) {
        e.preventDefault();
        sharedStimulusCreator.trigger('exit');
      });
      this.hide();
    },
    render() {
      var $container = this.getAreaBroker().getMenuLeftArea();
      $container.append(this.$element);
      this.show();
    },
    destroy() {
      this.$element.remove();
    },
    enable() {
      this.$element.removeProp('disabled').removeClass('disabled');
    },
    disable() {
      this.$element.prop('disabled', true).addClass('disabled');
    },
    show() {
      hider.show(this.$element);
    },
    hide() {
      hider.hide(this.$element);
    }
  });
});
