define('taoMediaManager/qtiCreator/renderers/Object',['lodash', 'taoQtiItem/qtiCommonRenderer/renderers/Object', 'taoMediaManager/qtiCreator/widgets/static/object/Widget'], function (_, Renderer, Widget) {
  'use strict';

  var CreatorObject = _.clone(Renderer);
  CreatorObject.render = function render(object, options) {
    Renderer.render(object);
    options = options || {};
    options.baseUrl = this.getOption('baseUrl');
    options.uri = this.getOption('uri');
    options.lang = this.getOption('lang');
    options.mediaManager = this.getOption('mediaManager');
    options.assetManager = this.getAssetManager();
    Widget.build(object, Renderer.getContainer(object), this.getOption('bodyElementOptionForm'), options);
  };
  return CreatorObject;
});
