define('taoMediaManager/controller/actions',['lodash', 'jquery', 'i18n', 'layout/actions/binder', 'uri', 'layout/section', 'core/request', 'core/router', 'core/logger', 'ui/feedback', 'ui/dialog/confirm', 'ui/dialog/alert', 'util/url', 'tpl!taoMediaManager/qtiCreator/tpl/relatedItemsPopup', 'tpl!taoMediaManager/qtiCreator/tpl/relatedItemsClassPopup', 'tpl!taoMediaManager/qtiCreator/tpl/forbiddenClassAction', 'css!taoMediaManagerCss/media.css'], function (_, $, __, binder, uri, section, request, router, loggerFactory, feedback, confirmDialog, alertDialog, urlUtil, relatedItemsPopupTpl, relatedItemsClassPopupTpl, forbiddenClassActionTpl) {
  'use strict';

  var overloadLimit = 15;
  var logger = loggerFactory('taoMediaManager/manageMedia');
  binder.register('newSharedStimulus', function instanciate(actionContext) {
    var self = this;
    var classUri = uri.decode(actionContext.classUri);
    return request({
      url: self.url,
      data: JSON.stringify({
        classUri: classUri
      }),
      method: 'POST'
    }).then(function (response) {
      if (actionContext.tree) {
        $(actionContext.tree).trigger('addnode.taotree', [{
          uri: uri.decode(response.data.id),
          label: response.data.name,
          parent: uri.decode(actionContext.classUri),
          cssClass: 'node-instance'
        }]);
      }
      return {
        uri: uri.decode(response.data.id),
        label: response.data.name,
        classUri: uri.decode(actionContext.classUri),
        type: 'instance'
      };
    }).catch(err => {
      if (!_.isUndefined(err.message)) {
        feedback().error(err.message);
      }
      logger.error(err);
    });
  });
  binder.register('sharedStimulusAuthoring', function sharedStimulusAuthoring(actionContext) {
    section.updateContentBlock('').create({
      id: 'authoring',
      name: __('Authoring'),
      url: this.url,
      content: ' ',
      visible: false
    }).show();
    var $panel = $('#panel-authoring');
    $panel.attr('data-id', actionContext.id);
    $panel.attr('data-uri', actionContext.uri);
    router.dispatch("".concat(this.url, "?id=").concat(actionContext.id));
  });
  binder.register('deleteSharedStimulus', function remove(actionContext) {
    var self = this;
    var data = {};
    var mediaRelationsData = {
      type: 'media'
    };
    if (actionContext.context[0] === 'instance') {
      mediaRelationsData.sourceId = actionContext.id;
    } else {
      mediaRelationsData.classId = actionContext.id;
    }
    data.uri = uri.decode(actionContext.uri);
    data.classUri = uri.decode(actionContext.classUri);
    data.id = actionContext.id;
    data.signature = actionContext.signature;
    return new Promise(function (resolve, reject) {
      request({
        url: urlUtil.route('index', 'ResourceRelations', 'tao'),
        data: mediaRelationsData,
        method: 'GET',
        noToken: true
      }).then(function (responseRelated) {
        var message;
        var haveItemReferences = responseRelated.data.relations;
        var name = $('a.clicked', actionContext.tree).text().trim();
        if (actionContext.context[0] === 'instance') {
          if (haveItemReferences.length === 0) {
            message = "".concat(__('Are you sure you want to delete this'), " <b>").concat(name, "</b>?");
            callConfirmModal(actionContext, message, self.url, data, resolve, reject);
          } else {
            var itemList = haveItemReferences;
            if (itemList.length > overloadLimit) {
              itemList = haveItemReferences.slice(0, overloadLimit);
            }
            message = relatedItemsPopupTpl({
              name,
              inUsageMessage: __('This "%s" is currently used in %d item(s)', name, haveItemReferences.length),
              items: itemList,
              overload: haveItemReferences.length > overloadLimit
            });
            callAlertModal(actionContext, message, self.url, data, resolve, reject);
          }
        } else if (actionContext.context[0] !== 'instance') {
          if (haveItemReferences.length === 0) {
            message = "".concat(__('Are you sure you want to delete this class and all of its content?'));
            callConfirmModal(actionContext, message, self.url, data, resolve, reject);
          } else if (haveItemReferences.length !== 0) {
            var _itemList = haveItemReferences;
            if (_itemList.length > overloadLimit) {
              _itemList = haveItemReferences.slice(0, overloadLimit);
            }
            message = relatedItemsClassPopupTpl({
              name,
              number: haveItemReferences.length,
              items: _itemList,
              overload: haveItemReferences.length > overloadLimit
            });
            callAlertModal(actionContext, message, self.url, data, resolve, reject);
          }
        }
      }).catch(errorObject => {
        var message;
        if (actionContext.context[0] === 'class' && errorObject.response.code === 999) {
          message = forbiddenClassActionTpl();
        }
        callAlertModal(actionContext, message, reject);
      });
    });
  });
  function callConfirmModal(actionContext, message, url, data, resolve, reject) {
    confirmDialog(message, () => accept(actionContext, url, data, resolve, reject), () => cancel(reject));
  }
  function callAlertModal(actionContext, message, reject) {
    alertDialog(message, () => cancel(reject));
  }
  function accept(actionContext, url, data, resolve, reject) {
    return request({
      url: url,
      method: 'POST',
      data: data,
      dataType: 'json'
    }).then(function (response) {
      if (response.success && response.deleted) {
        feedback().success(response.message || __('Resource deleted'));
        if (actionContext.tree) {
          $(actionContext.tree).trigger('removenode.taotree', [{
            id: actionContext.uri || actionContext.classUri
          }]);
        }
        return resolve({
          uri: actionContext.uri || actionContext.classUri
        });
      } else {
        if (response.success && !response.deleted) {
          $(actionContext.tree).trigger('refresh.taotree');
          reject(response.msg || response.message || __('Unable to delete the selected resource because you do not have the required rights to delete part of its content.'));
        }
        reject(response.msg || response.message || __('Unable to delete the selected resource'));
      }
    });
  }
  function cancel(reject) {
    reject({
      cancel: true
    });
  }
});
